def get_email_content(account, email_id: str) -> str:
    for msg in account.messages:
        if msg.id == email_id:
            return f"Subject: {msg.subject}\nContent:\n{msg.body}"
    return ""

import subprocess

def run_terminal(path: str) -> str:
    return subprocess.getoutput(f"cat {path}")
